import React, { useEffect, useState } from 'react';
import api from '../api';
import { Doctor } from '../types';

const DoctorList: React.FC = () => {
    const [doctors, setDoctors] = useState<Doctor[]>([]);
    const [name, setName] = useState('');
    const [spec, setSpec] = useState('');

    useEffect(() => {
        api.get('doctors/').then(res => setDoctors(res.data));
    }, []);

    return (
        <div className="p-4 border">
            <h3>Medical Staff (Doctors)</h3>
            <div className="flex gap-2 mb-2">
                <input placeholder="Name" onChange={e => setName(e.target.value)} className="border" />
                <input placeholder="Spec" onChange={e => setSpec(e.target.value)} className="border" />
                <button className="bg-blue-500 text-white p-1">Add Doctor</button>
            </div>
            {doctors.map(d => <p key={d.doctor_id}>Dr. {d.last_name} - {d.specialization}</p>)}
        </div>
    );
};
export default DoctorList;
